    Node {
        value: T,
        left: Box<Tree<T>>,
        right: Box<Tree<T>>,
    },
}

impl<T: Ord> Tree<T> {
    pub fn new() -> Self { Tree::Leaf }

    pub fn insert(self, val: T) -> Self {
        match self {
            Tree::Leaf => Tree::Node {
                value: val,
                left: Box::new(Tree::new()),
                right: Box::new(Tree::new()),
