pub enum OrderState {
    Pending,
    Confirmed { confirmed_at: u64 },
    Shipped { tracking: String },
    Delivered,
    Cancelled { reason: String },
}

impl OrderState {
    pub fn confirm(self, timestamp: u64) -> Result<Self, String> {
        match self {
            OrderState::Pending => Ok(OrderState::Confirmed { confirmed_at: timestamp }),
            _ => Err("Can only confirm pending orders".to_string()),
        }
    }

    pub fn ship(self, tracking: String) -> Result<Self, String> {
        match self {
            OrderState::Confirmed { .. } => Ok(OrderState::Shipped { tracking }),
            _ => Err("Can only ship confirmed orders".to_string()),
        }
    }

    pub fn deliver(self) -> Result<Self, String> {
        match self {
            OrderState::Shipped { .. } => Ok(OrderState::Delivered),
            _ => Err("Can only deliver shipped orders".to_string()),
        }
    }

    pub fn cancel(self, reason: String) -> Result<Self, String> {
        match self {
            OrderState::Delivered => Err("Cannot cancel delivered orders".to_string()),
            _ => Ok(OrderState::Cancelled { reason }),
        }
    }
}

