use std::thread;
use std::time::Duration;

pub fn retry<T, E, F: Fn() -> Result<T, E>>(
    f: F,
    max_attempts: u32,
    delay_ms: u64,
) -> Result<T, E> {
    let mut last_err: Option<E> = None;
    for attempt in 0..max_attempts {
        match f() {
            Ok(val) => return Ok(val),
            Err(e) => {
                last_err = Some(e);
                if attempt + 1 < max_attempts {
                    thread::sleep(Duration::from_millis(delay_ms));
                }
            },
        }
    }
    Err(last_err.unwrap())
}

