use std::sync::Arc;
use tokio::sync::mpsc;

pub trait MapReduceAgent {
    type Input;
    type Mapped;
    type Output;

    async fn map_fn(&self, input: Self::Input) -> Self::Mapped;
    fn reduce_fn(&self, items: Vec<Self::Mapped>) -> Self::Output;
}

pub async fn swarm_map_reduce<A: MapReduceAgent + Send + Sync + 'static>(
    agent: Arc<A>,
    inputs: Vec<A::Input>,
) -> A::Output
where
    A::Input: Send + 'static,
    A::Mapped: Send + 'static,
{
    let (tx, mut rx) = mpsc::channel(inputs.len());

    for input in inputs {
        let agent = agent.clone();
        let tx = tx.clone();
        tokio::spawn(async move {
            let mapped = agent.map_fn(input).await;
            let _ = tx.send(mapped).await;
        });
    }
    drop(tx);

    let mut results = Vec::new();
    while let Some(item) = rx.recv().await {
        results.push(item);
    }

    agent.reduce_fn(results)
}

