pub fn isqrt(n: u64) -> u64 {
    // pre: n <= u64::MAX
    // post: ret * ret <= n
    // post: (ret + 1) * (ret + 1) > n

    if n == 0 { return 0; }
    let mut x = n;
    let mut y = (x + 1) / 2;
    while y < x {
        x = y;
        y = (x + n / x) / 2;
    }
    x
}

