use clap::Parser;
use clap::Subcommand;

#[derive(Parser)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Command,
}

#[derive(Subcommand)]
pub enum Command {
    /// Create a new project
    New {
        /// Project name
        name: String,
        /// Use a template
        #[clap(long)]
        template: Option<String>,
    },
    /// Build the project
    Build {
        /// Build in release mode
        #[clap(long)]
        release: bool,
    },
    /// Run tests
    Test {
        /// Filter test names
        filter: Option<String>,
    },
}

pub fn main() {
    let cli = Cli::parse();
    match cli.command {
        Command::New { name, template } => {
            println!("Creating project: {name}");
            if let Some(t) = template {
                println!("Using template: {t}");
            }
        },
        Command::Build { release } => {
            println!("Building (release={release})");
        },
        Command::Test { filter } => {
            println!("Running tests");
            if let Some(f) = filter {
                println!("Filter: {f}");
            }
        },
    }
}
